/** State of a circuit breaker. */
export type CircuitBreakerState = 'closed' | 'open' | 'half-open';

/** Configuration for circuit breaker behavior. */
export interface CircuitBreakerConfig {
  /** Number of failures before the circuit opens. Default: 5 */
  readonly failureThreshold: number;
  /** Time in ms the circuit stays open before transitioning to half-open. Default: 30000 */
  readonly resetTimeoutMs: number;
  /** Number of consecutive successes in half-open state to close the circuit. Default: 3 */
  readonly halfOpenMaxAttempts: number;
  /** Rolling window in ms for failure counting. Default: 60000 */
  readonly monitorWindowMs: number;
}

/** Default circuit breaker configuration. */
export const DEFAULT_CIRCUIT_BREAKER_CONFIG: CircuitBreakerConfig = {
  failureThreshold: 5,
  resetTimeoutMs: 30_000,
  halfOpenMaxAttempts: 3,
  monitorWindowMs: 60_000,
};

/** Error thrown when the circuit breaker is open and rejects execution. */
export class CircuitBreakerOpenError extends Error {
  constructor(
    public readonly remainingMs: number,
  ) {
    super(`Circuit breaker is open. Retry after ${remainingMs}ms`);
    this.name = 'CircuitBreakerOpenError';
  }
}

interface FailureRecord {
  readonly timestamp: number;
}

/**
 * Circuit breaker implementing the closed → open → half-open → closed pattern.
 *
 * - **Closed:** All calls pass through. Failures are recorded in a rolling window.
 *   When failures within the window reach the threshold, the circuit opens.
 * - **Open:** All calls are rejected immediately with CircuitBreakerOpenError.
 *   After resetTimeoutMs, the circuit transitions to half-open.
 * - **Half-open:** A limited number of probe calls are allowed through.
 *   If they succeed consecutively, the circuit closes. Any failure re-opens it.
 */
export class CircuitBreaker {
  private _state: CircuitBreakerState = 'closed';
  private readonly config: CircuitBreakerConfig;
  private failures: FailureRecord[] = [];
  private openedAt = 0;
  private halfOpenSuccesses = 0;
  private readonly getNow: () => number;

  constructor(config?: Partial<CircuitBreakerConfig>, now?: () => number) {
    this.config = { ...DEFAULT_CIRCUIT_BREAKER_CONFIG, ...config };
    this.getNow = now ?? (() => Date.now());
  }

  /** Current circuit breaker state. */
  get state(): CircuitBreakerState {
    if (this._state === 'open') {
      const elapsed = this.getNow() - this.openedAt;
      if (elapsed >= this.config.resetTimeoutMs) {
        this._state = 'half-open';
        this.halfOpenSuccesses = 0;
      }
    }
    return this._state;
  }

  /**
   * Execute an async function through the circuit breaker.
   * Rejects immediately if the circuit is open.
   */
  async execute<T>(fn: () => Promise<T>): Promise<T> {
    const currentState = this.state;

    if (currentState === 'open') {
      const remaining = this.config.resetTimeoutMs - (this.getNow() - this.openedAt);
      throw new CircuitBreakerOpenError(Math.max(0, remaining));
    }

    try {
      const result = await fn();
      this.recordSuccess();
      return result;
    } catch (error) {
      this.recordFailure();
      throw error;
    }
  }

  /** Record a successful operation. */
  recordSuccess(): void {
    const currentState = this.state; // Triggers lazy open→half-open transition
    if (currentState === 'half-open') {
      this.halfOpenSuccesses++;
      if (this.halfOpenSuccesses >= this.config.halfOpenMaxAttempts) {
        this._state = 'closed';
        this.failures = [];
        this.halfOpenSuccesses = 0;
      }
    } else if (currentState === 'closed') {
      // Successful call in closed state; prune old failures
      this.pruneFailures();
    }
  }

  /** Record a failed operation. */
  recordFailure(): void {
    const now = this.getNow();
    const currentState = this.state; // Triggers lazy open→half-open transition

    if (currentState === 'half-open') {
      // Any failure in half-open immediately re-opens
      this._state = 'open';
      this.openedAt = now;
      this.halfOpenSuccesses = 0;
      return;
    }

    if (currentState === 'closed') {
      this.failures.push({ timestamp: now });
      this.pruneFailures();

      if (this.failures.length >= this.config.failureThreshold) {
        this._state = 'open';
        this.openedAt = now;
      }
    }
  }

  /** Reset the circuit breaker to closed state with no failure history. */
  reset(): void {
    this._state = 'closed';
    this.failures = [];
    this.openedAt = 0;
    this.halfOpenSuccesses = 0;
  }

  /** Number of failures in the current monitoring window. */
  get failureCount(): number {
    this.pruneFailures();
    return this.failures.length;
  }

  private pruneFailures(): void {
    const cutoff = this.getNow() - this.config.monitorWindowMs;
    this.failures = this.failures.filter(f => f.timestamp > cutoff);
  }
}
